+/// If the switch condition is a ucmp/scmp intrinsic, try to simplify the switch
+/// into an icmp and branch.
+static bool simplifySwitchOnCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder,
+                                         DomTreeUpdater *DTU) {
+  Value *Cond = SI->getCondition();
+  auto *CmpI = dyn_cast<CmpIntrinsic>(Cond);
+  if (!CmpI)
+    return false;

-bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
+  // ucmp/scmp returns -1, 0, or 1. Determine the destination for each.
+  BasicBlock *DefaultDest = SI->getDefaultDest();
+  BasicBlock *DestM1 = DefaultDest;
+  BasicBlock *Dest0 = DefaultDest;
+  BasicBlock *Dest1 = DefaultDest;
+
+  for (auto &Case : SI->cases()) {
+    ConstantInt *CaseVal = Case.getCaseValue();
+    if (CaseVal->isMinusOne())
+      DestM1 = Case.getCaseSuccessor();
+    else if (CaseVal->isZero())
+      Dest0 = Case.getCaseSuccessor();
+    else if (CaseVal->isOne())
+      Dest1 = Case.getCaseSuccessor();
+    else
+      return false; // Unexpected case value for ucmp/scmp
+  }
+
+  // If all destinations are the same, fold to unconditional branch.
+  if (DestM1 == Dest0 && Dest0 == Dest1) {
+    Builder.CreateBr(DestM1);
+    SI->eraseFromParent();
+    if (DTU)
+      DTU->applyUpdates({{DominatorTree::Insert, SI->getParent(), DestM1}});
+    return true;
+  }
+
+  Value *LHS = CmpI->getLHS();
+  Value *RHS = CmpI->getRHS();
+  BasicBlock *TrueDest, *FalseDest;
+  CmpInst::Predicate Pred;
+
+  if (DestM1 == Dest0) {
+    // -1 and 0 go to the same destination, 1 goes to the other.
+    // Condition: a > b (gt) → Dest1, else → DestM1
+    Pred = CmpI->isSigned() ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+    TrueDest = Dest1;
+    FalseDest = DestM1;
+  } else if (Dest0 == Dest1) {
+    // 0 and 1 go to the same destination, -1 goes to the other.
+    // Condition: a < b (lt) → DestM1, else → Dest0
+    Pred = CmpI->isSigned() ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+    TrueDest = DestM1;
+    FalseDest = Dest0;
+  } else if (DestM1 == Dest1) {
+    // -1 and 1 go to the same destination, 0 goes to the other.
+    // Condition: a == b → Dest0, else → DestM1
+    Pred = ICmpInst::ICMP_EQ;
+    TrueDest = Dest0;
+    FalseDest = DestM1;
+  } else {
+    // Three different destinations, can't simplify.
+    return false;
+  }
+
+  Value *Cmp = Builder.CreateICmp(Pred, LHS, RHS);
+  BranchInst *NewBI = Builder.CreateCondBr(Cmp, TrueDest, FalseDest);
+
+  // Update branch weights if present.
+  if (hasBranchWeightMD(*SI)) {
+    SmallVector<uint64_t, 8> Weights;
+    getBranchWeights(SI, Weights);
+    if (Weights.size() == 1 + SI->getNumCases()) {
+      uint64_t TrueWeight = 0;
+      uint64_t FalseWeight = 0;
+      for (size_t I = 0, E = Weights.size(); I != E; ++I) {
+        if (SI->getSuccessor(I) == TrueDest)
+          TrueWeight += Weights[I];
+        else
+          FalseWeight += Weights[I];
+      }
+      while (TrueWeight > UINT32_MAX || FalseWeight > UINT32_MAX) {
+        TrueWeight /= 2;
+        FalseWeight /= 2;
+      }
+      setBranchWeights(NewBI, TrueWeight, FalseWeight, /*IsExpected=*/false);
+    }
+  }
+
+  // Remove redundant PHI node entries.
   BasicBlock *BB = SI->getParent();
+  for (auto BBI = TrueDest->begin(); isa<PHINode>(BBI); ++BBI) {
+    unsigned PreviousEdges = 0;
+    for (unsigned I = 0, E = SI->getNumSuccessors(); I != E; ++I)
+      if (SI->getSuccessor(I) == TrueDest)
+        ++PreviousEdges;
+    for (unsigned I = 0, E = PreviousEdges > 0 ? PreviousEdges - 1 : 0; I != E; ++I)
+      cast<PHINode>(BBI)->removeIncomingValue(BB);
+  }
+  for (auto BBI = FalseDest->begin(); isa<PHINode>(BBI); ++BBI) {
+    unsigned PreviousEdges = 0;
+    for (unsigned I = 0, E = SI->getNumSuccessors(); I != E; ++I)
+      if (SI->getSuccessor(I) == FalseDest)
+        ++PreviousEdges;
+    for (unsigned I = 0, E = PreviousEdges > 0 ? PreviousEdges - 1 : 0; I != E; ++I)
+      cast<PHINode>(BBI)->removeIncomingValue(BB);
+  }
+
+  // Remove edges from DTU if needed.
+  if (DTU) {
+    SmallSetVector<BasicBlock *, 4> RemovedSuccessors;
+    for (unsigned I = 0, E = SI->getNumSuccessors(); I != E; ++I) {
+      BasicBlock *Succ = SI->getSuccessor(I);
+      if (Succ != TrueDest && Succ != FalseDest)
+        RemovedSuccessors.insert(Succ);
+    }
+    SmallVector<DominatorTree::UpdateType, 4> Updates;
+    Updates.push_back({DominatorTree::Insert, BB, TrueDest});
+    Updates.push_back({DominatorTree::Insert, BB, FalseDest});
+    for (BasicBlock *Succ : RemovedSuccessors)
+      Updates.push_back({DominatorTree::Delete, BB, Succ});
+    DTU->applyUpdates(Updates);
+  }

+  SI->eraseFromParent();
+  return true;
+}
